const item = $input.first().json;
const sAMAccountName = String(item.sAMAccountName || '').trim();
const dn = String(item.dn || '').trim();
const isEnabled = !!item.isEnabled;
const existing = item.existing || {};
const jobTitle = String(item.jobTitle || '').trim();
const studioRaw = String(item.studioRaw || '').trim();
const groups = Array.isArray(item.groups) ? item.groups : (item.groups ? [item.groups] : []);
const empId = String(item.empId || '').trim();
const phoneExt = String(item.phoneExt || '').trim();
const credentials = String(item.credentials || '').trim();
const homeFolder = !!item.homeFolder;

if (!sAMAccountName) throw new Error('sAMAccountName is required to update a user.');
if (!dn) throw new Error('dn is required to update a user.');

let company = '', city = '', state = '', zip = '', street = '', phone = '';
let newDn = dn;
const studioProvided = studioRaw !== '';
if (studioProvided) {
  const delimiter = studioRaw.includes(' ~~ ') ? ' ~~ ' : ' | ';
  const parts = studioRaw.split(delimiter).map(s => s.trim());
  const labelPart = parts[0] || '';
  street = parts[1] || '';
  state = parts[3] || '';
  zip = parts[4] || '';
  phone = parts[5] || '';
  const dashIdx = labelPart.indexOf(' — ');
  company = dashIdx !== -1 ? labelPart.substring(0, dashIdx).trim() : labelPart.trim();
  city = dashIdx !== -1 ? labelPart.substring(dashIdx + 3).trim() : '';
  if (!company) throw new Error(`Could not parse company from Studio value: ${studioRaw}`);
  if (!city) throw new Error(`Could not parse city from Studio value: ${studioRaw}`);
  const ouCity = city.replace(/[-\s]/g, '');
  const targetOU = `OU=${ouCity},OU=${company},OU=MGA USERS,DC=MGA,DC=com`;
  const existingCn = existing.cn || (dn.match(/^CN=([^,]+)/) || [])[1] || '';
  if (!existingCn) throw new Error('Could not determine existing CN to compute new DN for OU move.');
  newDn = `CN=${existingCn},${targetOU}`;
}

function valueOrExisting(submitted, existingVal) {
  const v = String(submitted ?? '').trim();
  if (v !== '') return v;
  const e = String(existingVal ?? '').trim();
  return e !== '' ? e : ' ';
}

const finalTitle = valueOrExisting(jobTitle, existing.title);
const finalCompany = valueOrExisting(company, existing.company);
const finalStreetAddress = valueOrExisting(street, existing.streetAddress);
const finalL = valueOrExisting(city, existing.l);
const finalSt = valueOrExisting(state, existing.st);
const finalPostalCode = valueOrExisting(zip, existing.postalCode);
const finalTelephoneNumber = valueOrExisting(phone, existing.telephoneNumber);

const optionalReplace = [];
if (empId) optionalReplace.push({ id: 'pager', value: empId });
if (phoneExt) optionalReplace.push({ id: 'ipPhone', value: phoneExt });
if (credentials) optionalReplace.push({ id: 'info', value: credentials });
if (homeFolder) {
  const bs = String.fromCharCode(92);
  optionalReplace.push({ id: 'homeDrive', value: 'Z:' });
  optionalReplace.push({ id: 'homeDirectory', value: bs + bs + 'mga.com' + bs + 'mga_files' + bs + 'scans' + bs + sAMAccountName });
}

const groupDns = groups.map(g => `CN=${g},OU=Security Groups,DC=MGA,DC=com`);

return [{ json: {
  sAMAccountName, dn, newDn, isEnabled, studioProvided,
  finalTitle, finalCompany, finalStreetAddress, finalL, finalSt, finalPostalCode, finalTelephoneNumber,
  optionalReplace, groupDns
} }];

const r = $('Resolve update fields').first().json;
const plainPassword = `MGAtemp${new Date().getFullYear()}`;
function encodePassword(password) {
  let encoded = '';
  const quoted = '"' + password + '"';
  for (let i = 0; i < quoted.length; i++) {
    encoded += String.fromCharCode(quoted.charCodeAt(i) & 0xFF, (quoted.charCodeAt(i) >>> 8) & 0xFF);
  }
  return encoded;
}
return [{ json: { newDn: r.newDn, unicodePwd: encodePassword(plainPassword) } }];

const a = $('Resolve update fields').first().json;
const userDn = a.newDn;
const desired = new Set(a.groupDns || []);
const current = new Set($input.all().filter(item => item.json && item.json.cn).map(item => `CN=${item.json.cn},OU=Security Groups,DC=MGA,DC=com`));

const actions = [];
for (const dn of desired) if (!current.has(dn)) actions.push({ groupDn: dn, action: 'add', userDn });
for (const dn of current) if (!desired.has(dn)) actions.push({ groupDn: dn, action: 'remove', userDn });

if (actions.length === 0) return [{ json: { action: 'noop', userDn } }];
return actions.map(item => ({ json: item }));

const r = $('Resolve update fields').first().json;
const errors = [];

function checkNode(name, label) {
  try {
    const j = $(name).first().json;
    if (j && j.error) errors.push(`${label}: ${j.error.message || j.error}`);
  } catch (e) {}
}

checkNode('LDAP: Move to correct OU', 'OU move');
checkNode('LDAP: Update attributes', 'Attribute update');
checkNode('LDAP: Set optional attributes', 'Optional attributes');
checkNode('LDAP: Enable account', 'Re-enable account');
checkNode('LDAP: Set password (existing)', 'Password reset');

for (const item of $input.all()) {
  if (item.json && item.json.error) {
    errors.push(`Group membership change (${item.json.groupDn || 'unknown group'}): ${item.json.error.message || item.json.error}`);
  }
}

return [{ json: { success: errors.length === 0, sAMAccountName: r.sAMAccountName, dn: r.newDn, reenabled: r.isEnabled === false, errors } }];

